# Task

Implement ToBamlValue for Option, Vec, and map types.

## File
`baml-bridge/crates/bridge/src/lib.rs` (or `to_value.rs`)

## Implementations

```rust
impl<T: ToBamlValue> ToBamlValue for Option<T> {
    fn to_baml_value(&self) -> BamlValue {
        match self {
            Some(v) => v.to_baml_value(),
            None => BamlValue::Null,
        }
    }
}

impl<T: ToBamlValue> ToBamlValue for Vec<T> {
    fn to_baml_value(&self) -> BamlValue {
        BamlValue::List(self.iter().map(|v| v.to_baml_value()).collect())
    }
}

impl<T: ToBamlValue> ToBamlValue for std::collections::HashMap<String, T> {
    fn to_baml_value(&self) -> BamlValue {
        let map: BamlMap<String, BamlValue> = self
            .iter()
            .map(|(k, v)| (k.clone(), v.to_baml_value()))
            .collect();
        BamlValue::Map(map)
    }
}

impl<T: ToBamlValue> ToBamlValue for std::collections::BTreeMap<String, T> {
    fn to_baml_value(&self) -> BamlValue {
        let map: BamlMap<String, BamlValue> = self
            .iter()
            .map(|(k, v)| (k.clone(), v.to_baml_value()))
            .collect();
        BamlValue::Map(map)
    }
}

// Box, Arc, Rc for convenience
impl<T: ToBamlValue> ToBamlValue for Box<T> {
    fn to_baml_value(&self) -> BamlValue {
        (**self).to_baml_value()
    }
}

impl<T: ToBamlValue> ToBamlValue for std::sync::Arc<T> {
    fn to_baml_value(&self) -> BamlValue {
        (**self).to_baml_value()
    }
}

impl<T: ToBamlValue> ToBamlValue for std::rc::Rc<T> {
    fn to_baml_value(&self) -> BamlValue {
        (**self).to_baml_value()
    }
}
```

